model User {
  id       String @id @default(uuid())
  email    String @unique
  password String
  role     String
}

model Restaurant {
  id       String     @id @default(uuid())
  name     String
  menuItems MenuItem[]
}

model MenuItem {
  id           String     @id @default(uuid())
  name         String
  price        Float
  restaurantId String
  restaurant   Restaurant @relation(fields: [restaurantId], references: [id])
}

model Order {
